/**
 * User facing options for the per-origin circuit breaker.
 *
 * Passed via the `circuitBreaker` request option, either as `true` (use all
 * defaults) or as a partial object overriding individual fields.
 */
export interface CircuitBreakerOptions {
  /** Consecutive failures required to move a `closed` circuit to `open`. */
  threshold: number;
  /** Milliseconds an `open` circuit waits before allowing a half-open probe. */
  cooldown: number;
  /** Maximum concurrent probes allowed while `half-open`. Defaults to `1`. */
  halfOpenMaxRequests?: number;
  /** Response statuses that count as circuit failures. */
  failureStatusCodes?: number[];
}

/** Fully resolved circuit breaker configuration (no optional fields). */
export interface ResolvedCircuitBreakerOptions
  extends Required<CircuitBreakerOptions> {}

export type CircuitBreakerInput = boolean | CircuitBreakerOptions | undefined;

export type CircuitStatus = "closed" | "open" | "half-open";

export interface CircuitState {
  status: CircuitStatus;
  /** Consecutive failures while `closed`. */
  failures: number;
  /** `Date.now()` timestamp of the last transition to `open`. */
  openedAt: number;
  /** In-flight probes while `half-open`. */
  halfOpenActive: number;
}

/** Per-origin state, shared across clients derived via `.create()`. */
export type CircuitStore = Map<string, CircuitState>;

/**
 * A handle bound to a single logical request (spanning internal retries).
 * The same handle is threaded through retry attempts so gating, probe-slot
 * accounting and failure recording happen exactly once per logical request.
 */
export interface CircuitHandle {
  origin: string;
  state: CircuitState;
  config: ResolvedCircuitBreakerOptions;
  /** Whether this logical request holds a half-open probe slot. */
  isProbe: boolean;
  /** Terminal outcome recorded (success/failure). */
  settled: boolean;
  /** Probe slot released. */
  released: boolean;
}

/** Symbol used to thread the active handle through retry option spreads. */
export const CIRCUIT_TOKEN: unique symbol = Symbol("ofetch.circuitBreaker");

// https://developer.mozilla.org/en-US/docs/Web/HTTP/Status
const DEFAULT_FAILURE_STATUS_CODES = [
  408, // Request Timeout
  409, // Conflict
  425, // Too Early (Experimental)
  429, // Too Many Requests
  500, // Internal Server Error
  502, // Bad Gateway
  503, // Service Unavailable
  504, // Gateway Timeout
];

const DEFAULTS: ResolvedCircuitBreakerOptions = {
  threshold: 5,
  cooldown: 30_000,
  halfOpenMaxRequests: 1,
  failureStatusCodes: DEFAULT_FAILURE_STATUS_CODES,
};

/**
 * Resolve the `circuitBreaker` request option into a full config, or
 * `undefined` when circuit tracking is disabled.
 */
export function resolveCircuitOptions(
  input: CircuitBreakerInput
): ResolvedCircuitBreakerOptions | undefined {
  if (!input) {
    return undefined;
  }
  if (input === true) {
    return DEFAULTS;
  }
  return {
    threshold: input.threshold ?? DEFAULTS.threshold,
    cooldown: input.cooldown ?? DEFAULTS.cooldown,
    halfOpenMaxRequests:
      input.halfOpenMaxRequests ?? DEFAULTS.halfOpenMaxRequests,
    failureStatusCodes:
      input.failureStatusCodes ?? DEFAULTS.failureStatusCodes,
  };
}

/**
 * Resolve the origin used to key circuit state from the effective request.
 * Returns `undefined` for inputs without a resolvable origin (for example a
 * relative string that was never rebased onto a `baseURL`).
 */
export function getRequestOrigin(request: FetchRequest): string | undefined {
  try {
    if (typeof request === "string") {
      return new URL(request).origin;
    }
    if (request instanceof URL) {
      return request.origin;
    }
    // Request instance (or Request-like with a `url`).
    const url = (request as Request)?.url;
    return url ? new URL(url).origin : undefined;
  } catch {
    return undefined;
  }
}

function getState(store: CircuitStore, origin: string): CircuitState {
  let state = store.get(origin);
  if (!state) {
    state = { status: "closed", failures: 0, openedAt: 0, halfOpenActive: 0 };
    store.set(origin, state);
  }
  return state;
}

/**
 * Attempt to acquire the circuit for a new logical request.
 *
 * Returns a {@link CircuitHandle} when the request may proceed (mutating the
 * state to reserve a probe slot when transitioning to / already `half-open`),
 * or `false` when the request must fast-fail.
 */
export function acquireCircuit(
  store: CircuitStore,
  origin: string,
  config: ResolvedCircuitBreakerOptions,
  now: number
): CircuitHandle | false {
  const state = getState(store, origin);

  // open -> half-open once the cooldown has elapsed.
  if (state.status === "open") {
    if (now - state.openedAt >= config.cooldown) {
      state.status = "half-open";
      state.halfOpenActive = 0;
    } else {
      return false;
    }
  }

  let isProbe = false;
  if (state.status === "half-open") {
    if (state.halfOpenActive >= config.halfOpenMaxRequests) {
      // Quota exceeded: additional probes fail fast.
      return false;
    }
    state.halfOpenActive++;
    isProbe = true;
  }

  return {
    origin,
    state,
    config,
    isProbe,
    settled: false,
    released: false,
  };
}

/** Record a successful logical request: reset failures and close the circuit. */
export function recordSuccess(handle: CircuitHandle): void {
  if (handle.settled) {
    return;
  }
  handle.settled = true;
  handle.state.failures = 0;
  handle.state.status = "closed";
}

